#!/bin/bash
set -e
rm -rf dist
mkdir -p dist
cp -R public/. dist/

cat > dist/styles.css << 'CSS'
:root{--navy:#0C1A2A;--navy2:#13263b;--blue:#2364FF;--orange:#FF7A1A;--gold:#D49A22;--gold-dark:#7C5313;--gold-soft:#FFF7E1;--white:#fff;--muted:#c7d6ef;--line:rgba(255,255,255,.10);--panel:rgba(255,255,255,.05);--panel2:rgba(255,255,255,.08)}
*{box-sizing:border-box}html{scroll-behavior:smooth}body{margin:0;font-family:Arial,Helvetica,sans-serif;background:linear-gradient(180deg,#081524 0%,#0C1A2A 45%,#13263b 100%);color:var(--white)}a{text-decoration:none;color:inherit}.wrap{max-width:1180px;margin:0 auto;padding:0 24px}.topbar{position:sticky;top:0;z-index:100;display:flex;align-items:center;justify-content:space-between;padding:16px 24px;background:rgba(12,26,42,.92);backdrop-filter:blur(12px);border-bottom:1px solid var(--line)}.brand{display:flex;align-items:center;gap:14px}.brand img{width:42px;height:42px}.brand strong{display:block;font-size:18px}.brand span{display:block;font-size:12px;color:#b8c8e6}.nav{display:flex;gap:10px;align-items:center;flex-wrap:wrap}.dropdown{position:relative}.dropbtn,.navlink,.btn{display:inline-flex;align-items:center;justify-content:center;gap:8px;padding:11px 14px;border-radius:12px;color:#dbe7ff;background:transparent;border:1px solid transparent;font-weight:700;cursor:pointer}.dropbtn:hover,.navlink:hover{background:rgba(255,255,255,.07)}.dropdown-menu{display:none;position:absolute;top:calc(100% + 8px);left:0;min-width:250px;padding:10px;background:#10233a;border:1px solid var(--line);border-radius:16px;box-shadow:0 18px 40px rgba(0,0,0,.3)}.dropdown:hover .dropdown-menu,.dropdown:focus-within .dropdown-menu{display:grid;gap:6px}.dropdown-menu a{padding:11px 12px;border-radius:12px;color:#dce7ff}.dropdown-menu a:hover{background:rgba(255,255,255,.07)}.btn-primary{background:var(--orange);color:#1b1209}.btn-secondary{border-color:#4c77ff}.hero{padding:74px 0 40px}.hero-grid{display:grid;grid-template-columns:1.15fr .85fr;gap:24px}.kicker{display:inline-flex;gap:8px;padding:8px 12px;border-radius:999px;background:rgba(35,100,255,.14);border:1px solid rgba(35,100,255,.35);color:#b9ceff;font-size:13px;font-weight:800}.kicker b{color:#fff}h1{font-size:clamp(38px,6vw,66px);line-height:1.02;margin:18px 0 16px}h2{font-size:32px;margin:0 0 12px}h3{margin:0 0 10px}.lead{font-size:18px;line-height:1.65;color:#d5e2fb}.cta-row{display:flex;gap:12px;flex-wrap:wrap;margin:24px 0 0}.signals{display:flex;gap:10px;flex-wrap:wrap;margin-top:16px}.signal{padding:8px 12px;border-radius:999px;background:rgba(255,255,255,.06);border:1px solid var(--line);font-size:13px;color:#d9e5fb}.card{background:var(--panel);border:1px solid var(--line);border-radius:20px;padding:22px;box-shadow:0 22px 60px rgba(0,0,0,.22)}.card p{margin:0;color:#c7d6ef;line-height:1.65}.grid-2,.grid-3,.grid-4,.grid-5{display:grid;gap:16px}.grid-2{grid-template-columns:repeat(2,minmax(0,1fr))}.grid-3{grid-template-columns:repeat(3,minmax(0,1fr))}.grid-4{grid-template-columns:repeat(4,minmax(0,1fr))}.grid-5{grid-template-columns:repeat(5,minmax(0,1fr))}.section{padding:28px 0}.list{display:grid;gap:8px}.row{display:flex;gap:10px;padding:10px 0;border-top:1px solid rgba(255,255,255,.08)}.row:first-child{border-top:0;padding-top:0}.dot{width:10px;height:10px;border-radius:50%;background:var(--orange);margin-top:6px;flex:0 0 10px}.price{font-size:34px;font-weight:900;color:#fff;margin:10px 0}.eyebrow{font-size:12px;letter-spacing:.08em;text-transform:uppercase;color:#9ec0ff;font-weight:800}.footer{padding:38px 0 64px;color:#bfd0ea}.footer p{line-height:1.65}.status{padding:14px 16px;border-radius:14px;background:rgba(35,100,255,.12);border:1px solid rgba(35,100,255,.28);color:#d9e4ff}.status.error{background:rgba(220,38,38,.16);border-color:rgba(248,113,113,.45);color:#ffe4e6}.status.success{background:rgba(34,197,94,.16);border-color:rgba(74,222,128,.45);color:#dcfce7}.form-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:16px}.field label{display:block;font-weight:700;margin-bottom:6px}.field input,.field select,.field textarea{width:100%;padding:12px 13px;border-radius:12px;border:1px solid #355075;background:#07111e;color:#fff}.field textarea{min-height:120px}.full{grid-column:1/-1}.small{font-size:13px;color:#9db4d8}.code{font-family:monospace;background:rgba(255,255,255,.06);padding:2px 6px;border-radius:6px}.marketing-note{border-left:4px solid var(--orange);padding-left:14px;color:#d7e3f6}.stage{padding:18px;border-radius:18px;background:var(--panel);border:1px solid var(--line)}.stage small{display:block;color:#8fb0ff;text-transform:uppercase;letter-spacing:.08em;margin-bottom:10px;font-weight:700}.stage strong{display:block;font-size:20px;margin-bottom:8px}.right-actions{display:flex;gap:12px;flex-wrap:wrap}.output{margin-top:14px;padding:16px;border-radius:14px;background:#07111e;border:1px solid #355075;min-height:170px;white-space:pre-wrap;color:#dce8ff}.hero-simple{padding:56px 0 20px}.logo-strip{display:flex;gap:18px;align-items:center;flex-wrap:wrap;margin-top:18px}.logo-mark{display:flex;align-items:center;gap:12px;padding:14px 16px;border:1px solid var(--line);border-radius:18px;background:rgba(255,255,255,.05)}.auricrux-mark{background:linear-gradient(135deg,rgba(212,154,34,.12) 0%,rgba(255,247,225,.08) 100%);border-color:rgba(212,154,34,.35)}.badge-gold{display:inline-block;padding:8px 12px;border-radius:999px;background:rgba(212,154,34,.14);border:1px solid rgba(212,154,34,.35);color:#ffd9a1;font-size:13px;font-weight:800}.plan-card{display:flex;flex-direction:column;gap:14px}.plan-card .cta-row{margin-top:auto}.muted{color:#c7d6ef}.gold{color:#ffd9a1}.feature-list{padding-left:18px;margin:0;color:#d9e5fb;line-height:1.7}.home-logo-wrap{display:flex;align-items:center;gap:22px;flex-wrap:wrap;margin-top:18px}.home-fca-logo{display:flex;align-items:center;gap:14px}.home-fca-logo img{width:56px;height:56px}.auricrux-token{width:56px;height:56px;border-radius:16px;background:linear-gradient(135deg,var(--gold-dark) 0%,var(--gold) 100%);display:flex;align-items:center;justify-content:center;color:#fff;font-size:28px;font-weight:900;box-shadow:0 14px 30px rgba(212,154,34,.25)}@media(max-width:960px){.hero-grid,.grid-2,.grid-3,.grid-4,.grid-5,.form-grid{grid-template-columns:1fr}.topbar{padding:14px 16px;align-items:flex-start;gap:12px;flex-direction:column}.wrap{padding:0 16px}.dropdown-menu{position:static;display:none;margin-top:8px}.dropdown:hover .dropdown-menu,.dropdown:focus-within .dropdown-menu{display:grid}}
