create_page(){
  path="$1"
  title="$2"
  body="$3"
  mkdir -p "dist$path"
  cat > "dist$path/index.html" <<HTML
<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8" />
<meta name="viewport" content="width=device-width, initial-scale=1" />
<title>$title</title>
<link rel="icon" type="image/svg+xml" href="/favicon.svg" />
<link rel="stylesheet" href="/styles.css" />
</head>
<body>
$header_markup
$body
$footer_markup
</body>
</html>
HTML
}

create_page "/" "Future Contractors of America | FCA Contractor Command" '
<main>
  <section class="hero">
    <div class="wrap hero-grid">
      <div>
        <div class="kicker"><b>Flagship product</b> FCA Contractor Command</div>
        <h1>Win better opportunities, present stronger proposals, and carry more work cleanly into execution.</h1>
        <p class="lead">FCA Contractor Command is built for contractors who want a sharper front-end revenue engine: cleaner intake, stronger bid continuity, clearer proposal movement, and a better transition from sales into real delivery.</p>
        <div class="cta-row">
          <a class="btn btn-primary" href="/pricing/">See Pricing</a>
          <a class="btn btn-secondary" href="/intake/">Start Intake</a>
          <a class="btn btn-secondary" href="/auricrux/">Meet Auricrux</a>
        </div>
        <div class="signals"><span class="signal">Marketing-only homepage</span><span class="signal">Clear product ladder</span><span class="signal">Auricrux-guided buying path</span><span class="signal">Single intake flow</span></div>
        <div class="home-logo-wrap">
          <div class="home-fca-logo"><img src="/favicon.svg" alt="FCA logo" /><div><strong>FCA</strong><div class="small">Future Contractors of America</div></div></div>
          <div class="logo-mark auricrux-mark"><div class="auricrux-token">A</div><div><strong class="gold">Auricrux</strong><div class="small">Guided command layer</div></div></div>
        </div>
      </div>
      <aside class="card">
        <h2>Why contractors buy FCA</h2>
        <div class="list">
          <div class="row"><span class="dot"></span><div><strong>Fewer dropped details</strong><p>Move from first contact to bid, proposal, and award with better continuity and less restart friction.</p></div></div>
          <div class="row"><span class="dot"></span><div><strong>Stronger buyer confidence</strong><p>Present a clearer commercial process to customers and decision-makers before the job is won.</p></div></div>
          <div class="row"><span class="dot"></span><div><strong>Auricrux in the loop</strong><p>Use Auricrux to explain value, compare packages, and guide the next step through the experience.</p></div></div>
        </div>
      </aside>
    </div>
  </section>
  <section class="section"><div class="wrap"><h2>One revenue path from intake to setup</h2><p>FCA is positioned to replace a messy stack of disconnected forms, spreadsheets, emails, and quote handoffs with one cleaner contractor experience that keeps the commercial path moving forward.</p><div class="grid-3"><article class="card"><h3>Capture interest earlier</h3><p>Give prospects a cleaner intake path that makes your company look more organized and more ready.</p></article><article class="card"><h3>Convert bids more cleanly</h3><p>Keep the commercial story connected from opportunity to estimate to proposal.</p></article><article class="card"><h3>Start jobs with less friction</h3><p>Carry the award result into the first operational setup step without losing the context you already worked to create.</p></article></div></div></section>
</main>'

create_page "/features" "FCA Features" '
<main class="hero-simple"><div class="wrap"><div class="kicker"><b>Product</b> Features</div><h1>Features that help contractors look sharper, move faster, and sell more cleanly.</h1><p class="lead">FCA Contractor Command is marketed around outcomes a contractor buyer can understand immediately: stronger intake, better bid continuity, clearer proposal flow, and a guided handoff into execution.</p><div class="grid-3 section"><article class="card"><h3>Guided intake</h3><p>Bring opportunities into a more professional front door that captures the right information early.</p></article><article class="card"><h3>Bid continuity</h3><p>Keep estimate and bid posture attached to the original opportunity instead of scattered across tools.</p></article><article class="card"><h3>Proposal support</h3><p>Strengthen the move from pricing and scope into an offer that is easier to present and easier to follow through on.</p></article><article class="card"><h3>Customer coordination</h3><p>Show customers a more organized experience from first contact through the next commercial step.</p></article><article class="card"><h3>Academy alignment</h3><p>Position training and operational readiness as part of the same growth system rather than a disconnected add-on.</p></article><article class="card auricrux-mark"><h3 class="gold">Auricrux guidance</h3><p>Use Auricrux to explain the product, recommend the right tier, and direct the next action.</p></article></div></div></main>'

